class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        # A number has exactly 2 proper divisors if and only if it is:
        # 1. The square of a prime number (e.g., 4 = 2^2, 9 = 3^2)
        # 2. The product of two distinct primes (e.g., 6 = 2 * 3)

        # So, we need to count numbers in [l, r] that are NOT:
        # - The square of a prime
        # - The product of two distinct primes

        # Total numbers in range
        total = r - l + 1

        # Count of special numbers in range
        special_count = 0

        # Sieve of Eratosthenes to find primes up to sqrt(r)
        max_prime = int(r**0.5) + 1
        is_prime = [True] * (max_prime + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(max_prime**0.5) + 1):
            if is_prime[i]:
                for j in range(i*i, max_prime + 1, i):
                    is_prime[j] = False

        # Count squares of primes in range
        for p in range(2, max_prime + 1):
            if is_prime[p]:
                square = p * p
                if l <= square <= r:
                    special_count += 1

        # Count products of two distinct primes in range
        for i in range(2, int(r**0.5) + 1):
            if is_prime[i]:
                for j in range(i + 1, max_prime + 1):
                    if is_prime[j]:
                        product = i * j
                        if l <= product <= r:
                            special_count += 1

        # Return count of non-special numbers
        return total - special_count
